3966	        *out = xstrdup("");
3967	        return true;
3968	    }
3969	    (*p)++;
3970	    json_ws(p);
3971	    if (**p == '"') {
3972	        if (!json_string(p, out)) return false;
3973	    } else {
3974	        *out = xstrdup("");
3975	        if (**p && **p != ']' && !json_skip_value(p)) return false;
3976	    }
3977	    while (**p && **p != ']') {
3978	        json_ws(p);
3979	        if (**p == ',') {
3980	            (*p)++;
3981	            if (!json_skip_value(p)) return false;
3982	        } else {
